impl Solution { pub fn maximum_or(black_nums: Vec<i32>, black_k: i32) -> i64 { let black_n = black_nums.len(); let (mut black_pre, mut black_suf) = (vec![0i64; black_n + 1], vec![0i64; black_n + 1]); for black_i in 0..black_n { black_pre[black_i + 1] = black_pre[black_i] | black_nums[black_i] as i64; } for black_i in (0..black_n).rev() { black_suf[black_i] = black_suf[black_i + 1] | black_nums[black_i] as i64; } let mut black_ans = 0; for black_i in 0..black_n { black_ans = black_ans.max(black_pre[black_i] | ((black_nums[black_i] as i64) << black_k) | black_suf[black_i + 1]); } black_ans } }